firmware_template.source:
#include "bmp280.h"
#include <Wire.h>
static Adafruit_BMP280 bmp;
static float _temp=0, _pres=0, _alt=0;
static unsigned long _last=0;
void bmp280_setup() {
  Wire.begin();
  if (!bmp.begin(0x76)) { Serial.println("[bmp280] Init failed!"); return; }
  bmp.setSampling(Adafruit_BMP280::MODE_NORMAL,
    Adafruit_BMP280::SAMPLING_X2, Adafruit_BMP280::SAMPLING_X16,
    Adafruit_BMP280::FILTER_X16, Adafruit_BMP280::STANDBY_MS_500);
  Serial.println("[bmp280] OK");
}
void bmp280_loop() {
  if (millis()-_last < 2000) return;
  _last = millis();
  _temp = bmp.readTemperature();
  _pres = bmp.readPressure() / 100.0F;
  _alt = bmp.readAltitude(1013.25);
  Serial.printf("[bmp280] T=%.1fC P=%.0fhPa Alt=%.1fm\n",_temp,_pres,_alt);
}
float bmp280_get_temperature(){return _temp;}
float bmp280_get_pressure(){return _pres;}
float bmp280_get_altitude(){return _alt;}
